for image_id_str, info in tqdm(pseudo_data.items()):
    image_id = int(image_id_str)

    fg_bboxes = info.get('foreground', {}).get('bbox', [])
    fg_categories = info.get('foreground', {}).get('category', [])
    fg_captions = info.get('foreground', {}).get('caption', [])

    for bbox, category_name, caption in zip(fg_bboxes, fg_categories, fg_captions):
        if category_name not in new_classes:
            continue
        
        if category_name not in name_to_id:
            max_cat_id += 1
            new_category = {
                'id': max_cat_id,
                'name': category_name,
                'synonyms': [category_name],
                'def': 'pseudo label class',
                'frequency': 'c',
                'image_count': 0,  # default
                'instance_count': 0,  # default
                'synset': f'{category_name.replace(" ", "_")}.n.01',
                'caption': caption
            }
            lvis_data['categories'].append(new_category)
            name_to_id[category_name] = max_cat_id

        category_id = name_to_id[category_name]
        area = bbox[2] * bbox[3]

        lvis_data['annotations'].append({
            'id': annotation_id,
            'image_id': image_id,
            'category_id': category_id,
            'bbox': bbox,
            'area': area,
            'segmentation': []
        })

        annotation_id += 1

